module RefModule (
  input clk,
  input reset,
  input [31:0] timer_duration,
  output reg timer_reset
);

reg [31:0] timer_count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
  if (reset) begin
    timer_count <= 0;
    timer_reset <= 0;
  end else begin
    timer_count <= timer_count + 1;
    if (timer_count >= timer_duration) begin
      timer_count <= 0;
      timer_reset <= 1;
    end else begin
      timer_reset <= 0;
    end
  end
end

endmodule
